import React from "react";
import "./Home.css";

export default function Home() {
  return (
    <div className="home-wrapper">

      {/* Logo from PUBLIC folder */}
      <img src="/prasa-logo.png" alt="Company Logo" className="home-logo" />

      <h2>PRASA Infocom & Power Solutions Pvt. Ltd.</h2>
      <p>Leading provider in power solutions, datacenter services, and IT infrastructure.</p>

      <div className="home-menu">
        <a className="home-btn" href="/profile">Profile</a>
        <a className="home-btn" href="/settings">Settings</a>
      </div>
    </div>
  );
}
